#
# | Тип / Структура     | Пам’ять (типова)      | Діапазон / Особливості          | Загальна інформація                                   | Приклад оголошення / присвоєння значення                            |
# | --------------------| --------------------- | ------------------------------- | ------------------------------------------------------| ------------------------------------------------------------------- |
# | int                 | Змінна (28–100+ байт) | Без обмежень (лише RAM)         | Цілі числа, підтримують довгі числа                   | a = 42                                                              |
# | float               | 24 байти              | \~±1.8×10³⁰⁸ (double precision) | Числа з плаваючою крапкою (64-bit)                    | b = 3.14                                                            |
# | complex             | \~32 байти            | Складні числа                   | Містить дійсну та уявну частини: a + bj               | z = 2 + 3j                                                          |
# | bool                | 24 байти              | True, False                     | Наслідує від int, де True == 1, False == 0            | flag = True                                                         |
# | str                 | 49+ байт + кодування  | Unicode рядки                   | Непереміщуваний, іммутабельний                        | s = "hello"                                                         |
# | bytes               | 33+ байти             | Послідовність байтів            | Іммутабельна байтова строка                           | b = b'abc'                                                          |
# | bytearray           | 56+ байти             | Як bytes, але змінна            | Мутабельна байтова послідовність                      | ba = bytearray(b'abc')                                              |
# | list                | 64+ байт + n \* 8     | Динамічна довжина               | Змінюваний масив об'єктів, швидкий доступ за індексом | lst = [1, 2, 3]                                                     |
# | tuple               | 48+ байт + n \* 8     | Незмінна послідовність          | Іммутабельний масив                                   | t = (1, 2, 3)                                                       |
# | set                 | \~216+ байт           | Унікальні елементи              | Хеш-таблиця, не підтримує індексацію                  | s = {1, 2, 3}                                                       |
# | frozenset           | \~216+ байт           | Незмінний set                   | Іммутабельна множина                                  | fs = frozenset([1, 2])                                              |
# | dict                | \~240+ байт           | Ключ-значення                   | Хеш-мапа, ключі — хешовані об'єкти                    | d = {'a': 1, 'b': 2}                                                |
# | range               | 48 байт               | Генерує послідовність int       | Лінива послідовність, займає мало пам’яті             | r = range(1, 1000)                                                  |
# | NoneType            | 16 байт               | Один об’єкт: None               | Представляє "нічого"                                  | x = None                                                            |
# | deque               | \~56 байт + n \* 8    | Подвійна черга                  | З collections; швидке вставлення з обох боків         | from collections import deque<br>dq = deque([1, 2])                 |
# | defaultdict         | \~240 байт            | dict з дефолтним значенням      | З collections; зручно для лічильників                 | from collections import defaultdict<br>dd = defaultdict(int)        |
# | Counter             | \~240 байт            | Частотний словник               | З collections; рахує кількість елементів              | from collections import Counter<br>c = Counter("abc")               |
# | OrderedDict         | \~240 байт            | dict з порядком вставки         | З collections; як dict, але запам'ятовує              |                                                                     |
# |                     |                       |                                 |   порядок (до Python 3.7)                             | from collections import OrderedDict<br>od = OrderedDict()           |
# | NamedTuple          | \~наближено як tuple  | Іменовані поля                  | З collections або typing; як tuple, але з полями      | from collections import                                             |
# |                     |                       |                                 |                                                       | namedtuple<br>Point = namedtuple('Point', 'x y')<br>p = Point(1, 2) | 
# | heapq -             |                       |                                 | 
# |(черга з пріоритетом)| \~list                | Мін-купа                        | З heapq; працює на базі списків                       | import heapq<br>heap = [3, 1, 2]<br>heapq.heapify(heap)             |
# | array               | Залежить від типу     | Масив одного типу               | З array (модуль); швидший та компактніший за list     | from array import array<br>a = array('i', [1, 2, 3])                |
# | queue.Queue         | \~256 байт            | Потокобезпечна черга            | З queue; для багатопотокових задач                    | from queue import Queue<br>q = Queue()                              |
# | LifoQueue/          |                       |                                 |                                                       |                                                                     |
# | PriorityQueue       | \~256 байт |          | Стек / черга з пріоритетом      | З queue; потокобезпечні реалізації                    | from queue import LifoQueue<br>s = LifoQueue()                      |
